const d = $input.first().json;
const { order_id, new_status, customer_phone, session_name, delivery_type, credit_amount, payment_link } = d;

let mensaje = '';

switch (new_status) {
  case 'pending_payment':
    if (payment_link) {
      mensaje = `✅ Tu pedido #${order_id} fue recibido. Para pagar con MercadoPago usá este link:\n${payment_link}`;
    } else {
      mensaje = `✅ Tu pedido #${order_id} fue recibido. ¡Estamos en eso!`;
    }
    break;
  case 'pending_preparation':
    mensaje = `✅ Tu pedido #${order_id} fue recibido. ¡Estamos en eso!`;
    break;
  case 'in_preparation':
    mensaje = `👨‍🍳 ¡Tu pedido #${order_id} está siendo preparado!`;
    break;
  case 'ready_for_dispatch':
    if (delivery_type === 'pickup') {
      mensaje = `📦 ¡Tu pedido #${order_id} está listo para retirar! Te esperamos.`;
    } else {
      mensaje = `📦 Tu pedido #${order_id} está listo y ya salió para entregarte. ¡En camino!`;
    }
    break;
  case 'in_delivery':
    mensaje = `🛵 Tu pedido #${order_id} está en camino. ¡Ya llega!`;
    break;
  case 'delivered':
    mensaje = `🎉 ¡Tu pedido #${order_id} fue entregado! Gracias por elegirnos.`;
    break;
  case 'cancelled':
    if (credit_amount && Number(credit_amount) > 0) {
      mensaje = `❌ Tu pedido #${order_id} fue cancelado. Tenés un crédito de $${credit_amount} para tu próximo pedido.`;
    } else {
      mensaje = `❌ Tu pedido #${order_id} fue cancelado. No se realizó ningún cobro.`;
    }
    break;
  case 'with_incident':
    mensaje = `⚠️ Tuvimos un inconveniente con tu pedido #${order_id}. Estamos resolviéndolo y te avisamos pronto.`;
    break;
  default:
    mensaje = '';
}

return [{ json: { mensaje, customer_phone, session_name, should_send: mensaje !== '' } }];
